VALUES
  ('dietitian-moex-04464', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有吞嚥障礙者，如需使用國際吞嚥障礙飲食標準化創辦組織（the International Dysphagia Diet Standardisation Initiative, IDDSI）第四級飲食，下列食物組合那一項較適宜？', '["糙米飯泥、紅蘿蔔泥、紅龍果泥、豆花", "糙米粥、紅蘿蔔粒、紅龍果泥、豆腐", "糙米飯、紅蘿蔔丁、紅龍果丁、板豆腐", "糙米飯泥、紅蘿蔔汁、紅龍果汁、豆漿"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "4a5f2c07c6ff", "answer_pdf_sha1": "ca5cb7bf2305", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04465', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '某團膳公司將白飯的蒸煮步驟列為重要管制點，並要求白飯蒸煮後之中心溫度要達85℃。下列何者符合食品 安全管制系統所述之驗效（Validation）？', '["管制界限訂定白飯蒸煮之中心溫度須達85℃以上才安全", "白飯蒸煮後若中心溫度未達85℃需重新加熱至90℃", "以金屬探針溫度計量測白飯蒸煮之中心溫度，確保達到85℃", "白飯蒸煮後中心溫度達85℃，經檢驗後未發現會造成食品腐敗或中毒之微生物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "09f1fe980802", "answer_pdf_sha1": "a8c8e65be46c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04466', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據食品安全管制系統準則之規定，下列何者正確？', '["同公司有兩個不同廠區（獨立廠址），只需成立一個管制小組以方便管理兩個廠區", "管制小組應該要確認產品的加工流程圖與生產現場作業一致，加工流程圖可簡要表示", "團體膳食業或餐飲業所設置專門職業人員可以由畜牧技師、獸醫師或水產養殖技師擔任", "未依規定設置專門職業人員之食品業者，依食品安全衛生管理法第47條第4款規定可處新臺幣3萬元以上300 萬元以下罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "09f1fe980802", "answer_pdf_sha1": "a8c8e65be46c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04467', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據食品用洗潔劑衛生標準，食品使用次氯酸鈉為消毒主成分，其殘留濃度以總有效氯計算為：', '["1 ppm以下", "2 ppm以下", "20 ppm以下", "200 ppm以下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "09f1fe980802", "answer_pdf_sha1": "a8c8e65be46c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04468', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者非屬食品良好衛生規範準則涵蓋之範圍？', '["從業人員", "作業場所", "設施衛生管理", "驗證制度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "09f1fe980802", "answer_pdf_sha1": "a8c8e65be46c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04469', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依我國法規規定，以輻射照射下列食品時，何者不以防治蟲害或殺菌為其主要目的：', '["綠豆", "生薑", "香辛料", "稻米"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "09f1fe980802", "answer_pdf_sha1": "a8c8e65be46c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04470', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據包裝食品營養標示應遵行事項規定，包裝食品之營養標示須標示糖含量，此處所稱之糖含量是指下列何 者？', '["10個碳數以下的低分子量醣類之總和", "葡萄糖等單醣之總和", "蔗糖等雙醣之總和", "單醣與雙醣之總和"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "09f1fe980802", "answer_pdf_sha1": "a8c8e65be46c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04471', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據食品安全衛生管理法，對於食品器具、食品容器或包裝的材質名稱及耐熱溫度之標示規定中，若為二種 以上材質組成者，應如何標示？', '["僅需標示材質所占比例最高者", "僅需標示最耐高溫者", "僅需標示最不耐高溫者", "應就各種材質分別標示"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "09f1fe980802", "answer_pdf_sha1": "a8c8e65be46c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04472', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '冷藏肉品表面形成黑色斑及產生霉味，可能是因為下列何種黴菌污染所導致？', '["青黴菌（Penicillium）", "沙雷氏菌（Serratia）", "麴菌（Aspergillus）", "梭黴菌（Fusarium）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "09f1fe980802", "answer_pdf_sha1": "a8c8e65be46c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04473', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '在廚房要預防金黃色葡萄球菌的污染，應特別注意：', '["餐具", "用水", "砧板", "手指之傷口、膿瘡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "09f1fe980802", "answer_pdf_sha1": "a8c8e65be46c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
